import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"护照丢失怎么办","description":"境外护照丢失的应急处理流程","frontmatter":{"title":"护照丢失怎么办","description":"境外护照丢失的应急处理流程"},"headers":[],"relativePath":"knowledge/safety/lost-passport.md","filePath":"knowledge/safety/lost-passport.md","lastUpdated":null}'),s={name:"knowledge/safety/lost-passport.md"};function l(n,a,i,d,p,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="护照丢失怎么办" tabindex="-1">护照丢失怎么办 <a class="header-anchor" href="#护照丢失怎么办" aria-label="Permalink to &quot;护照丢失怎么办&quot;">​</a></h1><h2 id="立即行动" tabindex="-1">立即行动 <a class="header-anchor" href="#立即行动" aria-label="Permalink to &quot;立即行动&quot;">​</a></h2><p>发现护照丢失后立即前往最近的警察局报案并获取报案证明。这是补办护照的必要文件。</p><h2 id="补办流程" tabindex="-1">补办流程 <a class="header-anchor" href="#补办流程" aria-label="Permalink to &quot;补办流程&quot;">​</a></h2><p>前往中国驻外使领馆申请补发护照。需提供报案证明、照片和身份证明文件，通常需要数个工作日。</p><h2 id="临时旅行证" tabindex="-1">临时旅行证 <a class="header-anchor" href="#临时旅行证" aria-label="Permalink to &quot;临时旅行证&quot;">​</a></h2><p>如需紧急回国可申请旅行证。旅行证办理更快但仅限回国使用，有效期较短。</p><h2 id="预防措施" tabindex="-1">预防措施 <a class="header-anchor" href="#预防措施" aria-label="Permalink to &quot;预防措施&quot;">​</a></h2><p>随身携带护照复印件和电子扫描件。护照和钱包分开存放，使用酒店保险箱保管重要证件。</p>',9)])])}const f=e(s,[["render",l]]);export{_ as __pageData,f as default};
